template.script:
(function() {
    var html = document.documentElement;
    var lang = html.getAttribute('lang') || '';
    if (lang.indexOf('ar') === 0) {
        html.setAttribute('dir', 'rtl');
    } else {
        html.setAttribute('dir', 'ltr');
    }
    function checkLoginPage() {
        var loginForm = document.querySelector('.oe_login_form');
        if (loginForm) {
            var ww = document.getElementById('wrapwrap');
            if (ww) ww.classList.add('alaj-login-active');
        }
    }
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', checkLoginPage);
    } else {
        checkLoginPage();
    }
})();
